/// <summary>
/// Asset Acquisition import
/// </summary>
public class ETG_Acu_AssetAcquisitionTransImport extends ETG_Acu_DataImportBase
{
    LedgerJournalId         journalNum;

}

Method.Source:
public static void main(Args args)
{
    ETG_Acu_AssetAcquisitionTransImport  assetAcquisitionTrans;

    assetAcquisitionTrans = ETG_Acu_AssetAcquisitionTransImport::construct();

    if (assetAcquisitionTrans.prompt())
    {
        assetAcquisitionTrans.runOperation();
    }
}

public static ETG_Acu_AssetAcquisitionTransImport construct()
{
    return new ETG_Acu_AssetAcquisitionTransImport();
}

/// <summary>
/// Describes whether the class is designed for execution in a new session.
/// </summary>
/// <returns>
/// true if the class is designed for execution the operation in a new session; otherwise, false.
/// </returns>
protected boolean canRunInNewSession()
{
    return false;
}

protected void processData(container _con)
{
    AssetJournalV2Entity    assetAcquisitionJournal;
    NumberSeq               numberSeq;

    if (!journalNum)
    {
        numberSeq = NumberSeq::newGetNum(LedgerParameters::numRefJournalNum());

        journalNum = numberSeq.num();
    }

    assetAcquisitionJournal.JournalBatchNumber              = journalNum;
    assetAcquisitionJournal.LineNumber                      = conpeek(_con, 2);
    assetAcquisitionJournal.AccountDisplayValue             = conpeek(_con, 3);
    assetAcquisitionJournal.AccountType                     = conpeek(_con, 4);
    assetAcquisitionJournal.CreditAmount                    = conpeek(_con, 5);
    assetAcquisitionJournal.CurrencyCode                    = conpeek(_con, 6);
    assetAcquisitionJournal.DebitAmount                     = conpeek(_con, 7);
    //assetAcquisitionJournal.DefaultDimensionDisplayValue    = conpeek(_con, 8);
    assetAcquisitionJournal.Description                     = conpeek(_con, 9);
    assetAcquisitionJournal.ExchangeRate                    = conpeek(_con, 10);
    assetAcquisitionJournal.JournalNameId                   = conpeek(_con, 11);
    assetAcquisitionJournal.OffsetAccountDisplayValue       = conpeek(_con, 12) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 24) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 22) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 26) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 25) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 20) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 23) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                                + conPeek(_con, 21);

    assetAcquisitionJournal.OffsetAccountType               = conpeek(_con, 13);
    assetAcquisitionJournal.PostingLayer                    = conpeek(_con, 14);
    assetAcquisitionJournal.Text                            = conpeek(_con, 15);
    assetAcquisitionJournal.TransactionType                 = conpeek(_con, 16);
    assetAcquisitionJournal.TransDate                       = str2Date(conpeek(_con, 17), 123);
    assetAcquisitionJournal.BookId                          = conpeek(_con, 18);
    assetAcquisitionJournal.Voucher                         = conpeek(_con, 19);

    // BusinessUnit (20)	Contract (21)	Department (22)	Intercompany (23)	Plant_Warehouse_Office (24)	Product_Service (25)	Trader_Employee (26)
    // |Plant_Warehouse_Office|Department|Trader_Employee|Product_Service|BusinessUnit|Intercompany|Contract

    assetAcquisitionJournal.DefaultDimensionDisplayValue  = conPeek(_con, 24) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 22) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 26) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 25) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 20) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 23) + enum2Str(dimensionParameters.DimensionSegmentDelimiter)
                                                + conPeek(_con, 21);
    assetAcquisitionJournal.insert();

}

/// <summary>
///Import inventory site
/// </summary>
/// <returns>Caption</returns>
public ClassDescription caption()
{
    ClassDescription ret;

    ret = 'Import asset acquisition';

    return ret;
}
